[ObservableTriggerAsync(nameof(SaveAsync))]
[ObservableTriggerAsync(nameof(ValidateAsync), nameof(CanValidate))]
public partial string Input { get; set; }

private async Task SaveAsync()
{
    await _repository.SaveAsync(Input);
}

private async Task ValidateAsync(CancellationToken ct)
{
    await _validator.ValidateAsync(Input, ct);
}

private bool CanValidate() => !string.IsNullOrEmpty(Input);

[ObservableTriggerAsync(nameof(SaveAsync))]
[ObservableTriggerAsync(nameof(ValidateAsync), nameof(CanValidate))]
public partial string Input { get; set; }

private async Task SaveAsync()
{
    await _repository.SaveAsync(Input);
}

private async Task ValidateAsync(CancellationToken ct)
{
    await _validator.ValidateAsync(Input, ct);
}

private bool CanValidate() => !string.IsNullOrEmpty(Input);

[ObservableTriggerAsync<string>(nameof(LogChangeAsync), "PropertyChanged")]
[ObservableTriggerAsync<int>(nameof(ValidateRangeAsync), 100, nameof(CanValidate))]
public partial int Count { get; set; }

private async Task LogChangeAsync(string message)
{
    await _logger.LogAsync($"{message}: {Count}");
}

private async Task ValidateRangeAsync(int maxValue, CancellationToken ct)
{
    if (Count > maxValue)
    {
        await _validator.ReportViolationAsync(Count, maxValue, ct);
    }
}

private bool CanValidate() => Count > 0;

